#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int floorX = (X + 9) / 10;
        int floorY = (Y + 9) / 10;
        int ans = abs(floorX - floorY);
        printf("%d\n", ans);
    }
    return 0;
}

